    +'<rect x="4" y="'+(sh2-7)+'" width="'+(sw2-8)+'" height="6" rx="2" fill="#64748b"/>'
    +'<rect x="4" y="'+(pd-2)+'" width="'+pw+'" height="'+(sh2-pd-5)+'" rx="2" fill="#64748b"/>'
    +'<rect x="'+(sw2-pw-4)+'" y="'+(pd-2)+'" width="'+pw+'" height="'+(sh2-pd-5)+'" rx="2" fill="#64748b"/>';
